











































































































































import _ from 'lodash';
import {
    Component,
    Prop,
    Vue,
    Watch,
} from 'vue-property-decorator';
import {
    State,
    Action
} from 'vuex-class';
import CardChoose from '@/components/CardChoose.vue';
import {
    countAll,
    CostPerformance
} from '@/utils/countUtil'
import {
    saveStr,
    effectStr,
} from '@/utils/stringUtil';

@Component({
    components: {
        CardChoose
    }
})
export default class Calculator extends Vue {
    private active: number = 1
    @State private calculator!: any
    @Action private SETCALCULATORGENERALDATA!: (value: any) => void
    @Action private SETCALCULATOREXTREMITYDATA!: (value: any) => void
    private $loading!: any
    private get initData() {
        return this.calculator.initData.reduce((a: any, b: any) => a.concat(b), [])
    }
    private get generalData() {
        return this.calculator.generalData.reduce((a: any, b: any) => a.concat(b), [])
    }
    private get extremityData() {
        return this.calculator.extremityData.reduce((a: any, b: any) => a.concat(b), [])
    }
    private get chunkData() {
        return _.chunk(this.calculator.initData, 2);
    }
    private get canglangComputed() {
        return this.calculator.operation.canglang
    }
    private set canglangComputed(newValue: any) {
        const val = newValue.replace(/[^\d]/g, '')
        this.calculator.operation.canglang = _.isEmpty(val) ? 0 : Number(val)
    }
    private get julingComputed() {
        return this.calculator.operation.juling
    }
    private set julingComputed(newValue: any) {
        const val = newValue.replace(/[^\d]/g, '')
        this.calculator.operation.juling = _.isEmpty(val) ? 0 : Number(val)
    }
    private effect(data: any) {
        const result = countAll(data);
        return effectStr(result);
    }
    private prev() {
        if (this.active < 2) {
            return
        }
        this.active--
    }
    private async next() {
        if (this.active === 3) {
            return
        }
        if (this.active === 2) {
            const loading = this.$loading({
                lock: true,
                text: 'Loading',
                spinner: 'el-icon-loading',
                background: 'rgba(0, 0, 0, 0.7)'
            });

            const reslut = await CostPerformance(this.calculator.initData, {
                canglang: this.canglangComputed,
                juling: 0,
                first: this.calculator.operation.first,
                second: this.calculator.operation.second
            })
            console.log('reslut:', reslut)
            this.SETCALCULATORGENERALDATA(reslut.generalData)
            this.SETCALCULATOREXTREMITYDATA(reslut.extremityData)
            loading.close()
        }
        this.active++
    }
    private TestBtn() {
        console.log('canglangComputed:', this.canglangComputed)
        console.log('first:', this.calculator.operation.first)
    }
}
